         *
         * Code specifying that the standard VAT rate is levied from the invoicee.
         */
        public const VAT_REVE_CHAR = 'AE';
        /**
         * Zero rated goods (Z)
         *
         * Code specifying that the goods are at a zero rate.
         */
        public const ZERO_RATE_GOOD = 'Z';
